public class CustomLootCondition implements LootCondition {
    @Override
    public LootConditionType getType() { return ModLootConditionTypes.CUSTOM; }
    @Override
    public boolean test(LootContext context) {
        return false;
    }
}

public class ParameterLootCondition implements LootCondition {
    private final int minScore;
    public ParameterLootCondition(int minScore) { this.minScore = minScore; }
    @Override
    public boolean test(LootContext context) {
        return context.get(LootContextParameters.THIS_ENTITY) instanceof PlayerEntity player && player.experienceLevel >= minScore;
    }
    public static Codec<ParameterLootCondition> getCodec() {
        return RecordCodecBuilder.create(instance -> instance.group(
            Codec.INT.fieldOf("min_score").forGetter(c -> c.minScore)
        ).apply(instance, ParameterLootCondition::new));
    }
}
